let data = null;

// 1) Try refined output first
try {
  data = {{LLMNode_852.output.generatedResponse}};
} catch (e) {}

// 2) If refined is empty, try fallback
if (!data) {
  try {
    data = {{LLMNode_249.output.generatedResponse}};
  } catch (e) {}
}

// 3) Nothing found
if (!data) {
  output = {
    result: {
      success: false,
      error: "No data received from Refine or Fallback node",
      raw: null
    }
  };
} else {
  // 4) If string, clean markdown fences
  if (typeof data === "string") {
    data = data
      .replace(/^```json\s*/i, "")
      .replace(/^```\s*/i, "")
      .replace(/\s*```$/i, "")
      .trim();

    try {
      data = JSON.parse(data);
    } catch (e) {
      output = {
        result: {
          success: false,
          error: "Invalid JSON returned from AI nodes",
          raw: data
        }
      };
    }
  }

  // 5) Final structure check
  if (data && data.days && Array.isArray(data.days) && data.days.length > 0) {
    output = {
      result: {
        success: true,
        destination: data.destination || "",
        country: data.country || "",
        introduction: data.introduction || "",
        best_time_to_visit: data.best_time_to_visit || "",
        estimated_budget: data.estimated_budget || "",
        highlights: data.highlights || [],
        food: data.food || [],
        culture: data.culture || [],
        travel_tips: data.travel_tips || [],
        days: data.days || []
      }
    };
  } else {
    output = {
      result: {
        success: false,
        error: "Lamatic returned JSON, but not in expected itinerary format.",
        raw: data
      }
    };
  }
}

